import json
import os
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
from google.auth import default
import functions_framework

# Initialize clients with default credentials (uses function's service account)
credentials, project_id = default()
storage_client = storage.Client(credentials=credentials, project=project_id)
firestore_client = firestore.Client(credentials=credentials, project=project_id)
publisher = pubsub_v1.PublisherClient(credentials=credentials)

# Use environment variables for configuration
FIRESTORE_COLLECTION = os.environ.get('FIRESTORE_COLLECTION', 'processed_files')
PUBSUB_TOPIC = os.environ.get('PUBSUB_TOPIC')
ALLOWED_BUCKETS = os.environ.get('ALLOWED_BUCKETS', '').split(',')

def validate_bucket(bucket_name):
    """Validate that the bucket is in the allowed list"""
    if not ALLOWED_BUCKETS or ALLOWED_BUCKETS == ['']:
        raise ValueError("ALLOWED_BUCKETS environment variable must be configured")
    if bucket_name not in ALLOWED_BUCKETS:
        raise ValueError(f"Bucket {bucket_name} is not in the allowed list")

def validate_file_path(file_path):
    """Validate file path to prevent path traversal"""
    if '..' in file_path or file_path.startswith('/'):
        raise ValueError(f"Invalid file path: {file_path}")

def sanitize_data(data):
    """Sanitize data before writing to Firestore"""
    # Limit data size
    max_size = 1048487  # Firestore document size limit minus overhead
    data_str = json.dumps(data)
    if len(data_str.encode('utf-8')) > max_size:
        raise ValueError("Data exceeds maximum allowed size")
    return data

@functions_framework.cloud_event
def process_storage_file(cloud_event):
    """
    Cloud Function triggered by Cloud Storage events.
    Uses principle of least privilege with scoped service account permissions.
    
    Required service account permissions (scoped to specific resources):
    - storage.objects.get on specific bucket(s)
    - datastore.entities.create on specific collection
    - pubsub.topics.publish on specific topic
    """
    
    try:
        data = cloud_event.data
        
        bucket_name = data.get('bucket')
        file_name = data.get('name')
        
        if not bucket_name or not file_name:
            raise ValueError("Missing bucket or file name in event data")
        
        # Validate bucket is allowed
        validate_bucket(bucket_name)
        
        # Validate file path
        validate_file_path(file_name)
        
        # Read file from Cloud Storage with size limit
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        # Check file size before downloading
        blob.reload()
        max_file_size = 10 * 1024 * 1024  # 10MB limit
        if blob.size > max_file_size:
            raise ValueError(f"File size {blob.size} exceeds maximum allowed size {max_file_size}")
        
        # Download with timeout
        file_content = blob.download_as_text(timeout=30)
        
        # Process and sanitize data
        processed_data = {
            'bucket': bucket_name,
            'file_name': file_name,
            'content_preview': file_content[:1000],  # Limit preview size
            'size': blob.size,
            'content_type': blob.content_type,
            'created': blob.time_created.isoformat() if blob.time_created else None,
            'updated': blob.updated.isoformat() if blob.updated else None
        }
        
        processed_data = sanitize_data(processed_data)
        
        # Write to Firestore with document ID validation
        doc_id = f"{bucket_name}_{file_name}".replace('/', '_').replace('.', '_')
        # Limit document ID length
        if len(doc_id) > 1500:
            doc_id = doc_id[:1500]
        
        doc_ref = firestore_client.collection(FIRESTORE_COLLECTION).document(doc_id)
        doc_ref.set(processed_data, merge=True)
        
        # Publish to Pub/Sub if topic is configured
        if PUBSUB_TOPIC:
            topic_path = publisher.topic_path(project_id, PUBSUB_TOPIC)
            
            message_data = {
                'bucket': bucket_name,
                'file_name': file_name,
                'status': 'processed',
                'doc_id': doc_id
            }
            
            # Publish with timeout
            future = publisher.publish(
                topic_path,
                json.dumps(message_data).encode('utf-8'),
                timeout=10
            )
            message_id = future.result(timeout=10)
            print(f"Published message {message_id} to {PUBSUB_TOPIC}")
        
        print(f"Successfully processed file: {file_name} from bucket: {bucket_name}")
        return {'status': 'success', 'doc_id': doc_id}
        
    except ValueError as e:
        print(f"Validation error: {str(e)}")
        raise
    except Exception as e:
        print(f"Error processing file: {str(e)}")
        raise


